func TestIndexerCreateAndStore(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "test.bleve")

	ix, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	defer ix.Close()

	chunks := []domain.Chunk{
		{
			QualifiedID:  "test-doc:A.1",
			SectionID:    "A.1",
			DocumentSlug: "test-doc",
			Title:        "First Section",
			Content:      "Content of first section.",
			Scope:        "global",
			Kind:         "reference",
			Tags:         []string{"tag1"},
			Position:     0,
			Vector:       make([]float32, 768),
		},
		{
			QualifiedID:  "test-doc:A.2",
			SectionID:    "A.2",
			DocumentSlug: "test-doc",
			Title:        "Second Section",
			Content:      "Content of second section.",
			Scope:        "global",
			Kind:         "reference",
			Tags:         []string{"tag2"},
			Position:     1,
			Vector:       make([]float32, 768),
		},
	}

	if err := ix.StoreChunks(chunks); err != nil {
		t.Fatalf("StoreChunks: %v", err)
	}

	count := ix.ChunkCount()
	if count != 2 {
		t.Errorf("ChunkCount = %d, want 2", count)
	}
}

func TestIndexerReopenExisting(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "persist.bleve")

	// Create and populate
	ix, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}

	chunks := []domain.Chunk{
		{
			QualifiedID:  "doc:s1",
			SectionID:    "s1",
			DocumentSlug: "doc",
			Title:        "Section 1",
			Content:      "Content one.",
			Scope:        "project",
			Kind:         "reference",
			Tags:         []string{},
			Position:     0,
			Vector:       make([]float32, 768),
		},
	}
	ix.StoreChunks(chunks)
	ix.Close()

	// Reopen
	ix2, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("Reopen: %v", err)
	}
	defer ix2.Close()

	count := ix2.ChunkCount()
	if count != 1 {
		t.Errorf("ChunkCount after reopen = %d, want 1", count)
	}
}

func TestIndexerRemoveDocument(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "remove.bleve")

	ix, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	defer ix.Close()

	chunks := []domain.Chunk{
		{
			QualifiedID:  "doc-a:s1",
			SectionID:    "s1",
			DocumentSlug: "doc-a",
			Title:        "Section 1",
			Content:      "Content A1.",
			Scope:        "project",
			Kind:         "reference",
			Tags:         []string{},
			Position:     0,
			Vector:       make([]float32, 768),
		},
		{
			QualifiedID:  "doc-a:s2",
			SectionID:    "s2",
			DocumentSlug: "doc-a",
			Title:        "Section 2",
			Content:      "Content A2.",
			Scope:        "project",
			Kind:         "reference",
			Tags:         []string{},
			Position:     1,
			Vector:       make([]float32, 768),
		},
		{
			QualifiedID:  "doc-b:s1",
			SectionID:    "s1",
			DocumentSlug: "doc-b",
			Title:        "Section 1",
			Content:      "Content B1.",
			Scope:        "global",
			Kind:         "decision",
			Tags:         []string{},
			Position:     0,
			Vector:       make([]float32, 768),
		},
	}

	ix.StoreChunks(chunks)

	if ix.ChunkCount() != 3 {
		t.Fatalf("expected 3 chunks before remove, got %d", ix.ChunkCount())
	}

	if err := ix.RemoveDocument("doc-a"); err != nil {
		t.Fatalf("RemoveDocument: %v", err)
	}

	if ix.ChunkCount() != 1 {
		t.Errorf("expected 1 chunk after remove, got %d", ix.ChunkCount())
	}
}

func TestIndexerHashTracking(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "hash.bleve")

	ix, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	defer ix.Close()

	content := []byte("original content")

	// First time: should be considered changed
	if !ix.HasChanged("doc.md", content) {
		t.Error("new document should be considered changed")
	}

	// Record hash
	ix.RecordHash("doc.md", content)

	// Same content: should not be changed
	if ix.HasChanged("doc.md", content) {
		t.Error("unchanged document should not be considered changed")
	}

	// Modified content: should be changed
	if !ix.HasChanged("doc.md", []byte("modified content")) {
		t.Error("modified document should be considered changed")
	}
}

func TestIndexerUpsertSemantics(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "upsert.bleve")

	ix, err := NewIndexer(path, 768)
	if err != nil {
		t.Fatalf("NewIndexer: %v", err)
	}
	defer ix.Close()

	chunk := domain.Chunk{
		QualifiedID:  "doc:s1",
		SectionID:    "s1",
		DocumentSlug: "doc",
		Title:        "Original Title",
		Content:      "Original content.",
		Scope:        "project",
		Kind:         "reference",
		Tags:         []string{},
		Position:     0,
		Vector:       make([]float32, 768),
	}

	ix.StoreChunks([]domain.Chunk{chunk})
	if ix.ChunkCount() != 1 {
		t.Fatalf("expected 1 chunk, got %d", ix.ChunkCount())
	}

	// Store again with same ID (upsert)
	chunk.Title = "Updated Title"
	chunk.Content = "Updated content."
	ix.StoreChunks([]domain.Chunk{chunk})

	if ix.ChunkCount() != 1 {
		t.Errorf("expected 1 chunk after upsert, got %d (duplicate detected)", ix.ChunkCount())
	}
}
